parameters.jsCode:
const item = $('Start').first().json;

const text = String(
  item?.message?.content_last_message ||
  item?.message?.content ||
  item?.last_user_message ||
  ''
).trim();

const historyText = String(
  item?.history_for_crm ||
  item?.message?.history_for_crm ||
  item?.historico ||
  ''
).trim();

const mergedText = [text, historyText].filter(Boolean).join('\n\n');

const statusAtual =
  item?.status_lead ||
  item?.memory?.status_lead ||
  item?.lead_status ||
  'NOVO_LEAD';

const ultimaIntencao =
  item?.ultima_intencao ||
  item?.memory?.ultima_intencao ||
  '';

const eventoSistema =
  item?.evento_sistema_atual ||
  item?.evento_sistema ||
  item?.memory?.evento_sistema_atual ||
  '';

const statusPagamento =
  item?.status_pagamento ||
  item?.memory?.status_pagamento ||
  'nao_solicitado';

const comprovanteRecebido =
  Number(item?.comprovante_recebido || item?.memory?.comprovante_recebido || 0) === 1 ||
  statusPagamento === 'comprovante_recebido' ||
  statusPagamento === 'validacao_humana_pendente' ||
  statusPagamento === 'aprovado_humano';

const hasPreviousBrunaMessage = Boolean(
  item?.data_ultima_mensagem_bruna ||
  item?.mensagem_ultima_bruna ||
  item?.memory?.mensagem_ultima_bruna ||
  item?.last_ai_message
);

const isFirstTurn = Boolean(
  item?.is_first_turn ??
  (
    (statusAtual === 'NOVO_LEAD' || !statusAtual) &&
    !hasPreviousBrunaMessage
  )
);

const asksInfo = /(mais informa[cç][õo]es|quero informa[cç][õo]es|poderia me passar mais informa[cç][õo]es|gostaria de saber mais|saber mais|como funciona)/i.test(text);

const comesFromTraffic = /(vim do site|vim do formul[aá]rio|vim do an[uú]ncio|vim da bio)/i.test(text);

const mentionsScheduleEval = /(agendar( a)? avalia[cç][ãa]o|quero agendar( a)? avalia[cç][ãa]o|agendar avalia[cç][ãa]o)/i.test(text);

const explicitAcceptEval = /(pode mandar o pix|manda o pix|pode enviar o pix|quero seguir com a avalia[cç][ãa]o|quero fazer a avalia[cç][ãa]o|vamos seguir com a avalia[cç][ãa]o|vamos fazer a avalia[cç][ãa]o|pode agendar|quero dar continuidade|vamos prosseguir)/i.test(text);

const asksInfoOrPrice = /(quanto|valor|di[aá]ria|estadia|hospedagem|hotel|mais informa[cç][õo]es|como funciona|pacote|datas?)/i.test(mergedText);

const stalePaymentState =
  statusAtual === 'AGUARDANDO_PAGAMENTO' ||
  ultimaIntencao === 'ACEITOU_AVALIACAO' ||
  eventoSistema === 'PIX_SOLICITADO';

const serviceHotel = /\bhotel\b/i.test(mergedText);
const serviceCreche = /\bcreche\b|\bauauzin\b|\bauau\b/i.test(mergedText);

let flowMode = 'NORMAL';

if (
  isFirstTurn &&
  (
    comesFromTraffic ||
    asksInfo ||
    (mentionsScheduleEval && !explicitAcceptEval)
  )
) {
  flowMode = 'OPENING_TRAFFIC';
} else if (
  stalePaymentState &&
  !comprovanteRecebido &&
  asksInfoOrPrice
) {
  flowMode = 'RECOVER_INFO';
}

item.inputs = item.inputs || {};
item.inputs.guardrails = {
  ...(item.inputs.guardrails || {}),
  flow_mode: flowMode,
  is_first_turn: isFirstTurn,
  block_pix_on_this_turn: flowMode === 'OPENING_TRAFFIC' || flowMode === 'RECOVER_INFO',
  block_schedule_on_this_turn: flowMode === 'OPENING_TRAFFIC' || flowMode === 'RECOVER_INFO',
  force_opening_with_intro_and_dog_question: flowMode === 'OPENING_TRAFFIC',
  force_answer_mode: flowMode === 'RECOVER_INFO' ? 'price_info_then_collect_dog' : '',
  explicit_accept_eval: explicitAcceptEval,
  force_intent: serviceHotel
    ? 'INTERESSE_HOTEL'
    : serviceCreche
      ? 'INTERESSE_CRECHE'
      : '',
  force_status:
    flowMode === 'OPENING_TRAFFIC'
      ? 'COLETANDO_DADOS'
      : flowMode === 'RECOVER_INFO'
        ? 'QUALIFICANDO'
        : '',
  force_event:
    flowMode === 'OPENING_TRAFFIC'
      ? 'FORMULARIO_RECEBIDO'
      : ''
};

if (flowMode === 'RECOVER_INFO') {
  item.status_lead = 'QUALIFICANDO';
  item.ultima_intencao = 'PEDIU_VALOR';
  item.evento_sistema_atual = '';
  item.status_pagamento = 'nao_solicitado';
  item.comprovante_recebido = 0;
}

return [{ json: item }];

